Hi @ggglyke!

There isn't anything built-in to do that, but you can use the filter events to do it ([demo](https://jsfiddle.net/rhefg0zs/)):

```js
$(function() {
  var ignore = false;
  var $table = $('table');
  $table
    .on('filterInit', function() {
      var $filters = $table.find('.tablesorter-filter');
      $filters.on('change', function() {
        if (!ignore) {
          ignore = true;
          $filters.not(this).val('');
        }
      })
    })
    .on('filterEnd', function() {
      ignore = false;
    })
    .tablesorter({
      theme: 'blue',
      widgets: ['zebra', 'filter'],
      widgetOptions: {
        filter_selectSource: {
          0: ['abc', 'zyx'],
          1: ['<=50', '>50']
        }
      }
    });
});
```

