```python
class Base(HasTraits):

    a = Something()
    
    def __init__(self, *force_notifiy):
        for c in force_notify:
            self.notify_change(c)
        # do something dependant
        # on post-notified state

class Mixin(object):

    def __init__(self, value):
        change = {'name': 'a', 'owner': self,
                  'old': self.a, 'type': 'change'}
        with self.mute_trait_notificaitons():
            self.a = value
        change['new'] = self.a
        super(Mixin, self).__init__(change)
        
def class_factory(klass):
    return type('FromFactory',
                (klass, Base))

inst = class_factory(Mixin)(#something)
```

