import logging
import warnings
from functools import wraps
logging.captureWarnings(True)
logging.basicConfig(level=logging.WARN,
                    format='%(asctime)s %(name)-12s %(levelname)-8s %(message)s',
                    datefmt='%m-%d %H:%M',
